<p data-start="1355" data-end="1567">Resmi istatistik kurumları, sektörel raporlar, iş dünyası dergileri, LinkedIn trend analizleri ve kariyer blogları faydalı kaynaklar arasında.</p>', '$.wp_published_at', '2025-09-11T10:39:02Z', '$.wp_modified_at', '2026-03-15T18:42:26Z', '$.featured_image', json('{"provider":"external","src":"/wp-content/uploads/2025/02/international-students-in-turkey.webp","alt":"Social life for international students studying at universities in Turkey.","title":"international-students-in-turkey"}')) WHERE "collection" = 'posts' AND "id" = ( SELECT "live_revision_id" FROM "ec_posts" WHERE "deleted_at" IS NULL AND "status" = 'published' AND "locale" = 'tr' AND "slug" = 'turkiyede-yukselen-is-alanlari-ve-trendler' );
